@Test
public void handlesXmlDeclWithClosingQuestionMark() {
    String xml = "<?xml version='1.0' encoding='UTF-8'?><root><val>Test</val></root>";
    Document doc = Jsoup.parse(xml, "", Parser.xmlParser());
    assertEquals("Test", doc.select("val").text());
}

@Test
public void handlesBogusCommentWithExclamation() {
    String xml = "<!DOCTYPE html><root><val>Content</val></root>";
    Document doc = Jsoup.parse(xml, "", Parser.xmlParser());
    assertEquals("Content", doc.select("val").text());
}

@Test
public void handlesXmlDeclWithAttributes() {
    String xml = "<?xml version='1.0' standalone='yes'?><data>Value</data>";
    Document doc = Jsoup.parse(xml, "", Parser.xmlParser());
    assertEquals("Value", doc.select("data").text());
}
